	elif matchMouse( parent.Camera.par.Panmouse, panelValue.name ) and \
		matchModifier( parent.Camera.par.Panmod, panelValue.owner.panel ):
		return "pan";

	return None;

# start the camera movement when the button is pressed
def offToOn(panelValue):

	if panelValue.name == "focusselect":
		return;

	valueName = panelValue.name
	panelOwner = panelValue.owner.panel

	u = panelOwner.u.val
	v = panelOwner.v.val

	mode = parent.Camera.par.Navigationmode;

	action = getCameraAction( panelValue );

	# the return value of the callback indicates if the click was handled or not
	handled = parent.Camera.SendCallback(u, v, valueName, True, action, False);

	if not (action is None) and not handled:
		parent.Camera.StartTransform(action=action, u=u, v=v, mode=mode);

	return

# move the camera while the button is pressed
def whileOn(panelValue):

	if panelValue.name == "focusselect":
		return;

	if parent.Camera.GetAction() is None:
		return

	valueName = panelValue.name
	panelOwner = panelValue.owner.panel

	u = panelOwner.u.val
	v = panelOwner.v.val

	# speed adjustments
	speedMult = 1.0;
	if parent.Camera.GetAction() == "tumble":
		speedMult = parent.Camera.par.Tumblemult;

	elif parent.Camera.GetAction() == "dolly":
		speedMult = parent.Camera.par.Dollymult;

	elif parent.Camera.GetAction() == "pan":
		speedMult = parent.Camera.par.Panmult;

	# do the transform
	parent.Camera.Transform(u=u, v=v, scaler=speedMult)

	return

# make sure the camera movement has ended	
def onToOff(panelValue):

	valueName = panelValue.name
	panelOwner = panelValue.owner.panel

	u = panelOwner.u.val
	v = panelOwner.v.val

	# make sure keyboard movement is stopped when the panel
	# loses focus since we won't get the key release messages
	if valueName == "focusselect":
		parent.Camera.ResetKeys();
		return;

	lastAction = parent.Camera.GetAction();

	cameraMoved = parent.Camera.EndTransform();

	handled = parent.Camera.SendCallback(u, v, valueName, False, lastAction, cameraMoved);

	# if the mouse was released without moving the camera
	if not cameraMoved and not handled:

		# if the right-button was released without moving, open the popup menu
		if panelValue.name == "rselect" and parent.Camera.par.Navmenu.eval():
			parent.Camera.OpenViewMenu();


	return;

# handle mouse wheel movements, they start and end in one action	
def valueChange(panelValue):

	valueName = panelValue.name
	panelOwner = panelValue.owner.panel

	uv = panelValue.owner.locateMouseUV();

	if valueName == 'wheel' and (panelOwner.wheel.val != 0) and \
		(uv[0] >= 0) and (uv[0] <= 1.0) and (uv[1] >= 0) and (uv[1] <= 1):

		mode = parent.Camera.par.Navigationmode;

		wheelAction = "wheel";
		if parent.Camera.par.Orthographic:
			wheelAction = "orthozoom";

		parent.Camera.StartTransform(action=wheelAction, u=uv[0], v=uv[1], mode=mode);

		parent.Camera.Transform( du=panelOwner.wheel * parent.Camera.par.Wheelmult.eval(), dv=0, scaler=1)

		parent.Camera.EndTransform();

	return
